import{_ as e,C as a,o as h,c as l,a3 as d,E as i}from"./chunks/framework.CjmLrUhD.js";const g=JSON.parse('{"title":"昊七七烤冷面 AI 爆款素材企业化最终定稿方案","description":"面向抖音电商优先场景，整合 AI Agent、飞书数字员工、浏览器自动化、封面实验、素材生产、人审边界和数据复盘的企业级爆款素材工作流。","frontmatter":{"title":"昊七七烤冷面 AI 爆款素材企业化最终定稿方案","description":"面向抖音电商优先场景，整合 AI Agent、飞书数字员工、浏览器自动化、封面实验、素材生产、人审边界和数据复盘的企业级爆款素材工作流。"},"headers":[],"relativePath":"ai-material-final-blueprint.md","filePath":"ai-material-final-blueprint.md","lastUpdated":1783645921000}'),o={name:"ai-material-final-blueprint.md"};function n(b,t,s,p,A,c){const r=a("AIMaterialFinalBlueprint");return h(),l("div",null,[t[0]||(t[0]=d('<h1 id="昊七七烤冷面-ai-爆款素材企业化最终定稿方案" tabindex="-1">昊七七烤冷面 AI 爆款素材企业化最终定稿方案 <a class="header-anchor" href="#昊七七烤冷面-ai-爆款素材企业化最终定稿方案" aria-label="Permalink to &quot;昊七七烤冷面 AI 爆款素材企业化最终定稿方案&quot;">​</a></h1><p>本方案面向昊七七烤冷面电商团队的真实经营场景，目标不是“用 AI 写几条爆款脚本”，而是建立一套可执行、可追踪、可复盘的企业级素材实验系统。它要求素材从情报进入、事实确认、封面实验、脚本分镜、视频制作、浏览器巡检、投放验证、数据回写、复盘入库形成连续闭环。</p><p>本方案所有经营判断均按“待验证假设”处理。外部资料只提供方法依据，不代表昊七七烤冷面已经获得相同结果。真正有效的规则只能来自公司自己的实验编号、投放数据、客服反馈、退款投诉、库存承接和毛利结果。</p><h2 id="一、研究依据" tabindex="-1">一、研究依据 <a class="header-anchor" href="#一、研究依据" aria-label="Permalink to &quot;一、研究依据&quot;">​</a></h2><table tabindex="0"><thead><tr><th>资料来源</th><th>可采纳依据</th><th>进入本方案的方式</th><th>证据性质</th></tr></thead><tbody><tr><td><a href="https://ads.tiktok.com/help/article/creative-best-practices" target="_blank" rel="noreferrer">TikTok Creative Best Practices</a></td><td>TikTok 建议广告创意保持平台原生表达，并持续补充多版本创意。</td><td>把爆款素材能力定义为持续实验系统，而不是单条灵感。</td><td>外部方法依据</td></tr><tr><td><a href="https://ads.tiktok.com/help/article/split-testing?lang=en" target="_blank" rel="noreferrer">TikTok Split Testing</a></td><td>Split test 要保持其他变量尽量一致，并拆分受众，以便判断不同版本表现。</td><td>封面、钩子、叙事、承接和投放设置必须拆开管理。</td><td>实验设计依据</td></tr><tr><td><a href="https://support.google.com/youtube/answer/12340300?hl=en" target="_blank" rel="noreferrer">YouTube 缩略图与标题建议</a></td><td>标题和缩略图应准确、简洁地代表内容。</td><td>封面被定义为“入口承诺”，必须能被视频开头兑现。</td><td>封面审核依据</td></tr><tr><td><a href="https://support.google.com/youtube/answer/7628154?hl=en" target="_blank" rel="noreferrer">YouTube CTR 解释</a></td><td>高点击但低观看时长，可能说明标题/缩略图与内容承接不一致。</td><td>封面 CTR 不能单独判胜；必须结合 3 秒留存和后续承接。</td><td>指标归因依据</td></tr><tr><td><a href="https://developers.openai.com/api/docs/guides/structured-outputs" target="_blank" rel="noreferrer">OpenAI Structured Outputs</a> / <a href="https://developers.openai.com/api/docs/guides/function-calling" target="_blank" rel="noreferrer">Function Calling</a></td><td>模型可以按结构化格式输出，并通过工具调用连接业务系统。</td><td>Agent 输出必须进入飞书字段，而不是散落在聊天记录里。</td><td>系统实现依据</td></tr><tr><td><a href="https://developers.openai.com/api/docs/guides/tools-computer-use" target="_blank" rel="noreferrer">OpenAI Computer Use</a></td><td>Computer Use 应运行在隔离环境，使用域名/动作白名单，高影响动作保留人工确认。</td><td>浏览器自动化只能做巡检、截图、下载、预填；发布、付款、删除、放量必须人审。</td><td>自动化安全依据</td></tr><tr><td><a href="https://playwright.dev/" target="_blank" rel="noreferrer">Playwright</a></td><td>Playwright 可驱动浏览器，适合测试、脚本和 Agent 工作流中的可靠网页自动化。</td><td>确定性、可重复的网页动作优先交给 Playwright/RPA。</td><td>自动化技术依据</td></tr><tr><td><a href="https://www.feishu.cn/hc/zh-CN/articles/697278684206-%E5%BF%AB%E9%80%9F%E4%B8%8A%E6%89%8B%E5%A4%9A%E7%BB%B4%E8%A1%A8%E6%A0%BC" target="_blank" rel="noreferrer">飞书多维表格</a></td><td>多维表格可作为在线数据库管理记录、视图和协作流程。</td><td>把实验主表、事实包、资产库、审核记录、投放回写和知识规则库放到同一数据底座。</td><td>企业化落地依据</td></tr><tr><td><a href="https://www.feishu.cn/hc/zh-CN/articles/643175485940-%E4%BD%BF%E7%94%A8%E5%B7%A5%E4%BD%9C%E6%B5%81%E7%9A%84-ai-agent-%E8%8A%82%E7%82%B9" target="_blank" rel="noreferrer">飞书工作流 AI Agent 节点</a> / <a href="https://www.feishu.cn/content/article/7631864469689240764" target="_blank" rel="noreferrer">飞书 aily</a></td><td>飞书支持在工作流中使用 AI Agent 节点，并提供团队数字员工能力。</td><td>将情报整理、脚本候选、合规初筛、复盘摘要接入工作流节点。</td><td>流程编排依据</td></tr><tr><td><a href="https://scjgj.beijing.gov.cn/zwxx/scjgdt/202510/t20251021_4234743.html" target="_blank" rel="noreferrer">普通食品广告合规红线</a></td><td>食品广告应真实合法，不得虚假，不得涉及疾病预防、治疗功能；非保健食品不得声称保健功能。</td><td>昊七七烤冷面素材禁止医疗化、功效化、绝对化和伪真实表达。</td><td>强约束</td></tr></tbody></table><h2 id="二、最终原则" tabindex="-1">二、最终原则 <a class="header-anchor" href="#二、最终原则" aria-label="Permalink to &quot;二、最终原则&quot;">​</a></h2><table tabindex="0"><thead><tr><th>原则</th><th>定稿表述</th></tr></thead><tbody><tr><td>一个目标</td><td>建立可持续发现爆款素材元素的企业系统，而不是承诺每条素材都会爆。</td></tr><tr><td>一个数据底座</td><td>所有假设、素材、封面、投放、评论、合规、复盘必须进入同一套飞书多维表格。</td></tr><tr><td>一个变量纪律</td><td>同一轮实验只改变可归因变量；封面、钩子、叙事、承接、投放设置不得混测。</td></tr><tr><td>一个 AI 边界</td><td>AI 可以检索、生成、预填、检查、归因、催办；事实、合规、价格、库存、发布和放量由人确认。</td></tr><tr><td>一个自动化原则</td><td>优先自动化重复网页动作和结构化字段动作；凡涉及账号、付款、发布、改价、放量、删除、授权，必须人审。</td></tr></tbody></table><h2 id="三、系统总架构" tabindex="-1">三、系统总架构 <a class="header-anchor" href="#三、系统总架构" aria-label="Permalink to &quot;三、系统总架构&quot;">​</a></h2><p>最终系统不按“视频部门单点生产”设计，而按七个能力层设计。每一层都有明确输入、自动化能力和业务输出。</p><table tabindex="0"><thead><tr><th>能力层</th><th>输入范围</th><th>AI/自动化能力</th><th>业务输出</th></tr></thead><tbody><tr><td>信息感知层</td><td>竞品、评论、热词、平台趋势、后台数据、客服记录</td><td>情报 Agent、评论洞察 Agent、浏览器巡检脚本、WebSearch</td><td>把散乱信息转成假设库。</td></tr><tr><td>事实约束层</td><td>SKU、规格、价格、库存、毛利、发货、资质、禁用词</td><td>事实包校验 Agent、字段完整性检查、冲突检测</td><td>没有事实包不进入生成和发布。</td></tr><tr><td>创意生产层</td><td>封面、钩子、脚本、分镜、口播、二创、评论区回复</td><td>脚本 Agent、封面 Agent、分镜 Agent、AIGC 图像/视频工具</td><td>批量生成候选，人工收敛为可投版本。</td></tr><tr><td>流程编排层</td><td>飞书状态流、任务催办、审核流、阻塞提醒、版本记录</td><td>飞书数字员工、工作流 AI Agent 节点、自动提醒</td><td>减少等待和漏项。</td></tr><tr><td>浏览器自动化层</td><td>创意中心、竞品页面、店铺后台、投放后台、数据报表、商品页核对</td><td>Playwright、Computer Use、RPA 脚本、截图归档</td><td>替代重复网页操作，不替代高影响决策。</td></tr><tr><td>投放验证层</td><td>小量上线、样本资格、指标回写、异常归因、评论风险</td><td>投放归因 Agent、数据回写脚本、日报生成</td><td>把市场反馈写回实验编号。</td></tr><tr><td>知识沉淀层</td><td>胜因、败因、适用条件、失效条件、下一轮 Prompt 和规则</td><td>知识库 Agent、规则库自动草稿、复盘摘要</td><td>让经验可复用、可失效、可更新。</td></tr></tbody></table><h2 id="四、多维时序图" tabindex="-1">四、多维时序图 <a class="header-anchor" href="#四、多维时序图" aria-label="Permalink to &quot;四、多维时序图&quot;">​</a></h2><p>一份素材实验启动后，各部门不是顺序排队，而是围绕事实包、候选生产、合规审核、小量投放和数据复盘并行推进。下图展示运营、供应链、客服、工厂、AI Agent、设计、视频、浏览器自动化、合规、投放、数据等小组在同一轮工作中的相对进度。</p>',12)),i(r),t[1]||(t[1]=d('<p>关键读法：</p><ul><li>AI Agent 在事实包确认前可以做情报整理和候选生成草稿，但不能进入发布稿。</li><li>设计/视频可以并行制作，但发布前必须经过合规与事实复核。</li><li>投放后台可由浏览器自动化预填，最终发布和预算由人确认。</li><li>数据回写、评论监控、供应链承接必须同步观察。</li><li>样本不足时只记录趋势，不写胜负结论。</li></ul><h2 id="五、最终工作流" tabindex="-1">五、最终工作流 <a class="header-anchor" href="#五、最终工作流" aria-label="Permalink to &quot;五、最终工作流&quot;">​</a></h2><table tabindex="0"><thead><tr><th>动作</th><th>目标</th><th>AI 加速能力</th><th>浏览器自动化能力</th><th>人工关口</th><th>输出</th></tr></thead><tbody><tr><td>1. 情报进入</td><td>收集竞品、评论、热词、历史数据、后台异常。</td><td>自动聚类、摘要、发现候选假设。</td><td>巡检公开页面、创意中心、竞品页，按白名单截图归档。</td><td>运营确认哪些情报进入假设库。</td><td>情报样本包</td></tr><tr><td>2. 事实包锁定</td><td>确认 SKU、价格、库存、毛利、规格、发货、资质。</td><td>检查缺字段和互相矛盾的承诺。</td><td>核对商品页、后台库存、活动价页面截图。</td><td>供应链、品控、店铺运营确认。</td><td>事实包</td></tr><tr><td>3. 实验立项</td><td>选择本轮变量和样本口径。</td><td>生成实验矩阵、固定变量、失败归因口径。</td><td>创建飞书实验记录并预填字段。</td><td>运营负责人锁定实验单。</td><td>实验设计单</td></tr><tr><td>4. 候选生产</td><td>生成封面、钩子、脚本、分镜、二创方向。</td><td>批量产出候选并自检禁用词、事实一致性。</td><td>把候选稿写入素材资产库。</td><td>设计、视频、运营筛选可投版本。</td><td>候选稿池</td></tr><tr><td>5. 素材制作</td><td>完成封面、开头、成片、商品承接话术。</td><td>生成剪辑清单、字幕稿、封面文案、客服回复初稿。</td><td>检查画面安全区、链接可访问、封面文字可读性。</td><td>设计/视频最终制作。</td><td>可审素材</td></tr><tr><td>6. 发布前审核</td><td>审核食品合规、事实承诺、价格库存、AI 伪真实风险。</td><td>合规 Agent 做初筛并给风险等级。</td><td>自动打开素材、商品页、活动页做逐项核对。</td><td>合规、品控、负责人拥有否决权。</td><td>审核记录</td></tr><tr><td>7. 小量上线</td><td>低预算验证入口、留存、承接、转化。</td><td>生成计划命名、投放备注、监测字段。</td><td>预填投放后台，最终发布/预算由人确认。</td><td>投放负责人发布。</td><td>投放计划</td></tr><tr><td>8. 数据回写</td><td>按实验编号回收曝光、点击、留存、成交、评论、退款。</td><td>判断样本资格和异常层级。</td><td>下载报表、读取后台指标、保存截图。</td><td>数据组确认口径。</td><td>数据回写表</td></tr><tr><td>9. 复盘决策</td><td>判断淘汰、观察、二创、放量、合规暂停。</td><td>生成胜败因草稿和下一轮建议。</td><td>拉取素材、报表、评论截图形成复盘附件。</td><td>运营负责人决策，供应链确认放量承接。</td><td>复盘结论</td></tr><tr><td>10. 规则入库</td><td>沉淀可复用规律和失效条件。</td><td>知识库 Agent 写规则草案，更新 Prompt。</td><td>给相关素材和实验编号打标签。</td><td>运营负责人批准正式规则。</td><td>知识规则库</td></tr></tbody></table><h2 id="六、实验矩阵" tabindex="-1">六、实验矩阵 <a class="header-anchor" href="#六、实验矩阵" aria-label="Permalink to &quot;六、实验矩阵&quot;">​</a></h2><p>第一轮真实执行时，建议把五类变量拆开验证。封面入口、前 3 秒钩子、视频叙事、商品/链接承接、投放归因分别回答不同问题。</p><table tabindex="0"><thead><tr><th>实验组</th><th>核心问题</th><th>固定变量</th><th>实验变量</th><th>样本要求</th><th>负责人</th><th>主指标</th><th>失败归因</th></tr></thead><tbody><tr><td>A. 封面入口组</td><td>在相同视频内容下，哪类封面更能让目标用户愿意点进来？</td><td>视频正文、投放计划、目标人群、SKU、价格、发布时间段尽量一致。</td><td>封面画面、封面标题、主体大小、利益点、场景表达。</td><td>同一条核心视频至少配置结果前置、价格利益、工厂信任、场景代入 4 类封面。</td><td>封面/设计组 + 运营研究组</td><td>封面 CTR、点击后 3 秒留存、负反馈、评论质疑。</td><td>点击率低判入口吸引不足；点击高留存低判入口承诺与视频开头不一致。</td></tr><tr><td>B. 前 3 秒钩子组</td><td>用户是否愿意在信息流中停下来继续看？</td><td>封面、后段视频结构、SKU、价格承诺、链接承接尽量一致。</td><td>开头 3 秒第一画面、第一句话、字幕密度、动作强度、结果是否前置。</td><td>同一卖点生成成品先出、价格先出、痛点先出、工厂先出、反常识先出等版本。</td><td>视频制作组 + 脚本 Agent</td><td>3 秒留存、5 秒留存、前段滑走率、评论是否复述钩子。</td><td>3 秒留存低说明开头没有足够强画面或强理由；若 CTR 也低，回到封面组。</td></tr><tr><td>C. 视频叙事组</td><td>用户看完后是否理解“为什么现在要买昊七七烤冷面”？</td><td>封面方向、前 3 秒钩子、SKU、价格和投放设置尽量一致。</td><td>叙事顺序、镜头密度、制作过程、人物出镜、工厂画面、场景冲突。</td><td>同一钩子至少测试夜宵制作、家庭囤货、源头工厂 3 种叙事。</td><td>视频制作组 + 工厂素材组 + 分镜 Agent</td><td>完播率、平均观看时长、互动率、收藏率、评论问题类型。</td><td>完播低检查节奏和信息顺序；互动高但加购低，说明购买理由不足。</td></tr><tr><td>D. 商品/链接承接组</td><td>用户点击或看完后，是否被商品页、价格、评价、规格和客服话术承接住？</td><td>素材版本和投放设置尽量一致。</td><td>商品标题、主图、详情页顺序、优惠表达、规格组合、客服快捷回复。</td><td>胜出素材对应至少 2 套承接链路：价格囤货型、品质信任型。</td><td>店铺运营 + 供应链 + 客服</td><td>收藏加购率、转化率、客服咨询率、退款/差评苗头、库存预警。</td><td>点击和留存正常但成交低，优先检查链接承接，不直接否定素材。</td></tr><tr><td>E. 投放归因组</td><td>结果差异来自素材，还是来自人群、预算、计划结构或平台流量波动？</td><td>控制计划结构、预算、定向、出价和投放周期。</td><td>仅在需要时单独测试人群、出价或预算策略，不与素材变量混杂。</td><td>每个素材实验编号映射唯一投放记录，避免无法追溯。</td><td>投放/数据组</td><td>曝光、点击、CTR、CPM、CPC、3 秒留存、完播、加购、成交、ROI。</td><td>样本不足或流量来源差异过大时，只记录趋势，不下最终结论。</td></tr></tbody></table><h2 id="七、封面生成协议" tabindex="-1">七、封面生成协议 <a class="header-anchor" href="#七、封面生成协议" aria-label="Permalink to &quot;七、封面生成协议&quot;">​</a></h2><p>封面必须作为独立实验变量，不应只是视频截图。封面的任务是形成准确的入口承诺，并让视频开头立刻兑现。</p><table tabindex="0"><thead><tr><th>封面类型</th><th>待验证假设</th><th>生成方向</th><th>固定条件</th><th>审核风险</th><th>指标</th></tr></thead><tbody><tr><td>结果前置型</td><td>用户先看到成品状态，更容易判断是否值得点开。</td><td>近景成品烤冷面，酱汁、切面和热气清楚，主体占画面 60% 以上，文字只写一个结果承诺。</td><td>视频内容、SKU、价格和投放人群保持一致。</td><td>成品必须与真实可制作效果一致，不能用豪华加料伪装基础款。</td><td>封面 CTR、3 秒留存、评论是否质疑图文不符。</td></tr><tr><td>价格利益型</td><td>囤货和低单顿成本会降低决策门槛。</td><td>多袋装、冰箱或家庭餐桌场景，明确规格和活动利益，文字短而可核验。</td><td>价格、规格、优惠时间必须与链接一致。</td><td>活动价结束后不能继续使用旧封面；不得写全网最低、永久有效、亏本清仓。</td><td>CTR、加购率、成交率、客服价格咨询量。</td></tr><tr><td>工厂信任型</td><td>食品用户对源头、卫生、发货稳定性有明显顾虑。</td><td>生产线、质检、打包、仓库、发货画面，标题强调真实工厂或真实打包过程。</td><td>所有画面来自真实工厂或经授权素材。</td><td>不得暗示超出资质范围的安全背书，不得使用绝对化安全承诺，不得伪造工厂或证书。</td><td>CTR、完播、评论信任问题、转化率。</td></tr><tr><td>场景代入型</td><td>夜宵、宿舍、家庭囤货等具体场景比泛卖点更容易触发点击。</td><td>人物手部动作、锅具或餐桌道具、明确场景短句，画面保留生活真实感。</td><td>场景人群与投放人群保持一致。</td><td>避免过度摆拍，避免把个别场景包装成普遍承诺；儿童/老人场景需更严格复核。</td><td>CTR、3 秒留存、收藏率、评论自我代入表达。</td></tr></tbody></table><p>封面审核红线：</p><ul><li>不得把 AI 生成的工厂、检测、证书、用户评价画面伪装为真实资产。</li><li>不得用普通食品制造治疗、保健、减肥、调理疾病等暗示。</li><li>不得把过期价格、库存或活动权益继续作为入口承诺。</li><li>不得把高点击直接等同于胜出，必须结合 3 秒留存和承接指标。</li></ul><h2 id="八、ai-替代与加速边界" tabindex="-1">八、AI 替代与加速边界 <a class="header-anchor" href="#八、ai-替代与加速边界" aria-label="Permalink to &quot;八、AI 替代与加速边界&quot;">​</a></h2><p>AI 替代的不是“部门责任”，而是部门内部可重复、可结构化、低风险的信息劳动。AI 可以让每个部门从手工整理、重复填写和低价值搜索中释放出来，但不能替代经营责任和法律责任。</p><table tabindex="0"><thead><tr><th>能力等级</th><th>可覆盖动作</th><th>适合替代/加速的劳动</th><th>边界</th><th>处理方式</th></tr></thead><tbody><tr><td>可自动执行</td><td>竞品公开页巡检、素材库截图归档、报表下载、字段完整性检查、日报生成、状态催办。</td><td>重复网页操作、固定格式整理、机械提醒、只读数据归档。</td><td>不涉及账号高权限、不改变业务状态、不对外发布。</td><td>自动运行，异常进入人工队列。</td></tr><tr><td>可自动预填</td><td>飞书实验单、投放计划命名、商品页核对清单、素材审核记录、复盘报告草稿。</td><td>字段录入、格式统一、版本编号、材料归集。</td><td>预填不等于提交，所有高影响动作前停住。</td><td>人确认后提交。</td></tr><tr><td>可自动初筛</td><td>食品合规风险、封面承诺兑现、价格库存冲突、素材变量混杂、样本不足。</td><td>规则扫描、风险标注、证据定位、异常提醒。</td><td>初筛只给风险等级和证据，不给最终放行。</td><td>合规/负责人判定。</td></tr><tr><td>可自动生成</td><td>封面标题、脚本、钩子、分镜、评论回复、二创方向、详情页承接文案。</td><td>候选扩散、结构化改写、表达变体、素材复用。</td><td>必须绑定事实包和禁用词；不允许伪造真实工厂、用户评价、检测证书。</td><td>人工筛选和改写。</td></tr><tr><td>必须人工决策</td><td>价格、库存、资质、发布、放量、停投、退款投诉处理、账号授权、付款、删除。</td><td>不适合替代，只能提供材料和建议。</td><td>属于经营责任、法律责任或不可逆动作。</td><td>AI 只能提示和准备材料。</td></tr></tbody></table><h2 id="九、浏览器自动化能力清单" tabindex="-1">九、浏览器自动化能力清单 <a class="header-anchor" href="#九、浏览器自动化能力清单" aria-label="Permalink to &quot;九、浏览器自动化能力清单&quot;">​</a></h2><p>浏览器自动化适合处理网页后台里重复、可记录、可回滚或只读的动作。对于不稳定 UI、强账号权限、最终发布、付款、删除、放量和授权动作，只能作为人审前辅助。</p><table tabindex="0"><thead><tr><th>场景</th><th>自动化动作</th><th>输出</th><th>边界</th></tr></thead><tbody><tr><td>竞品巡检</td><td>按白名单打开竞品商品页、直播切片页、短视频页，截图并记录价格、封面、开头、评论质疑。</td><td>新增竞品样本、异常价格、评论痛点。</td><td>只抓公开或已授权可看的信息，不绕过登录和反爬限制。</td></tr><tr><td>创意中心观察</td><td>定时访问平台创意中心或广告灵感页，收集热门结构、标题形式、画面表达。</td><td>趋势样本、可验证假设。</td><td>只作为灵感拆解，不照搬素材。</td></tr><tr><td>商品页一致性核对</td><td>打开商品详情页、活动价、优惠券、库存和发货承诺页面，对照事实包。</td><td>价格/库存/规格不一致预警。</td><td>不自动改价、不自动改库存。</td></tr><tr><td>投放后台辅助</td><td>预填计划名称、实验编号、素材 ID、预算备注，截图确认设置。</td><td>待人工确认的投放草稿。</td><td>最终发布、预算增加、停投必须人确认。</td></tr><tr><td>数据报表下载</td><td>按实验编号进入后台下载或复制曝光、点击、留存、成交、花费数据。</td><td>投放数据回写表。</td><td>口径变更需数据负责人确认。</td></tr><tr><td>评论与客服监控</td><td>巡检评论区、客服咨询、退款原因，聚类为疑虑、好评、差评、误导风险。</td><td>评论洞察和客服话术建议。</td><td>不自动代表品牌回复高风险评论。</td></tr><tr><td>页面视觉 QA</td><td>打开最终商品页和素材页，检查图片是否加载、文字是否遮挡、移动端是否可读。</td><td>页面截图和问题清单。</td><td>只做检查，不替代设计负责人验收。</td></tr><tr><td>复盘证据归档</td><td>把投放后台、商品页、评论区、素材版本截图绑定到实验编号。</td><td>可审计证据链。</td><td>截图需标注采集时间和账号范围。</td></tr></tbody></table><h2 id="十、数字员工编队" tabindex="-1">十、数字员工编队 <a class="header-anchor" href="#十、数字员工编队" aria-label="Permalink to &quot;十、数字员工编队&quot;">​</a></h2><table tabindex="0"><thead><tr><th>数字员工</th><th>职责</th><th>工具</th><th>写入位置</th><th>禁止动作</th></tr></thead><tbody><tr><td>情报数字员工</td><td>每日巡检竞品、平台趋势、评论和历史素材。</td><td>浏览器自动化、WebSearch、飞书多维表格</td><td>假设库、竞品样本库</td><td>不能照搬竞品素材。</td></tr><tr><td>事实包数字员工</td><td>检查 SKU、价格、库存、规格、发货、毛利、资质缺口。</td><td>飞书表格、商品后台只读、浏览器截图</td><td>事实包状态、冲突预警</td><td>不能修改价格库存。</td></tr><tr><td>创意生产数字员工</td><td>生成封面、钩子、脚本、分镜、二创方向。</td><td>LLM、图像生成工具、资产库</td><td>素材资产库、候选稿字段</td><td>不能伪造真实场景和证据。</td></tr><tr><td>合规初筛数字员工</td><td>扫描食品广告禁区、绝对化表达、价格不一致、AI 伪真实。</td><td>规则库、素材文本、截图 OCR</td><td>审核记录表风险等级</td><td>不能最终放行。</td></tr><tr><td>浏览器自动化员工</td><td>执行白名单网页巡检、下载、截图、预填、可用性测试。</td><td>Playwright、Computer Use、RPA</td><td>证据附件、报表文件、预填草稿</td><td>不能提交高影响动作。</td></tr><tr><td>投放归因数字员工</td><td>判断样本资格、异常层级、下一轮变量。</td><td>投放数据表、评论表、素材变量表</td><td>复盘草稿、决策建议</td><td>不能决定放量。</td></tr><tr><td>知识库数字员工</td><td>把胜因、败因、适用条件、失效条件写入规则库。</td><td>复盘表、素材库、审核表</td><td>知识规则库、Prompt 规则</td><td>规则正式生效需运营批准。</td></tr></tbody></table><h2 id="十一、飞书数据底座" tabindex="-1">十一、飞书数据底座 <a class="header-anchor" href="#十一、飞书数据底座" aria-label="Permalink to &quot;十一、飞书数据底座&quot;">​</a></h2><table tabindex="0"><thead><tr><th>数据表</th><th>关键字段</th><th>自动化规则</th></tr></thead><tbody><tr><td>素材实验主表</td><td>实验编号、SKU、人群、变量、状态、负责人、当前阻塞、结论。</td><td>状态变化触发催办、人审、投放和复盘任务。</td></tr><tr><td>事实包表</td><td>价格、库存、规格、毛利、发货、资质、保质期、可证明卖点。</td><td>任一关键字段未确认时阻塞素材生成和发布。</td></tr><tr><td>素材资产库</td><td>封面、脚本、分镜、成片、二创、来源、授权、关联实验。</td><td>胜出组件自动标记为高价值资产。</td></tr><tr><td>浏览器自动化任务表</td><td>任务名称、域名白名单、动作类型、账号权限、运行时间、截图证据、异常结果。</td><td>自动运行后写入证据和异常，遇到高影响动作停住等人审。</td></tr><tr><td>审核记录表</td><td>审核对象、风险等级、命中规则、修改建议、审核人、复核时间。</td><td>未通过审核时实验状态退回。</td></tr><tr><td>投放数据回写表</td><td>计划 ID、素材 ID、曝光、点击、留存、成交、ROI、退款、投诉、评论摘要。</td><td>达到样本或异常条件后触发复盘。</td></tr><tr><td>知识规则库</td><td>规则类型、内容、适用条件、失效条件、引用实验、置信度、维护人。</td><td>复盘通过后生成规则草案，人审后生效。</td></tr></tbody></table><p>建议状态流：</p><table tabindex="0"><thead><tr><th>状态</th><th>定义</th><th>责任人</th><th>流转条件</th></tr></thead><tbody><tr><td>草稿</td><td>实验单新建但事实包未锁定。</td><td>运营研究</td><td>进入待事实确认。</td></tr><tr><td>待事实确认</td><td>SKU、价格、库存、发货、规格未确认。</td><td>供应链/品控/店铺运营</td><td>缺任一关键事实不得进入制作。</td></tr><tr><td>待素材制作</td><td>事实包已通过，进入封面和开头制作。</td><td>设计/视频/AI Agent</td><td>产出实验单元。</td></tr><tr><td>待合规审核</td><td>素材已完成但未过审。</td><td>合规/负责人</td><td>未通过不得发布。</td></tr><tr><td>可投放</td><td>素材、事实、承接页均已确认。</td><td>投放</td><td>进入小量测试。</td></tr><tr><td>测试中</td><td>计划已上线并回写数据。</td><td>投放/数据</td><td>不足样本不得判断胜负。</td></tr><tr><td>复盘中</td><td>达到观察窗口或预算上限。</td><td>数据/运营</td><td>输出结论和下轮动作。</td></tr><tr><td>二创/放量/归档</td><td>形成下一动作。</td><td>运营负责人</td><td>放量前再次确认库存、价格和客服承接。</td></tr></tbody></table><h2 id="十二、人审与安全门" tabindex="-1">十二、人审与安全门 <a class="header-anchor" href="#十二、人审与安全门" aria-label="Permalink to &quot;十二、人审与安全门&quot;">​</a></h2><table tabindex="0"><thead><tr><th>关口</th><th>规则</th></tr></thead><tbody><tr><td>事实门</td><td>没有 SKU、价格、库存、规格、发货、资质确认，不允许生成发布稿。</td></tr><tr><td>合规模</td><td>出现疾病治疗、保健功效、绝对化、未证实数据、AI 伪真实，直接退回。</td></tr><tr><td>账号门</td><td>浏览器自动化不得读取密码、绕过登录、扩大权限、保存凭证。</td></tr><tr><td>发布门</td><td>投放发布、预算增加、改价、改库存、删除、授权、付款必须人工确认。</td></tr><tr><td>样本门</td><td>样本不足时只观察，不写胜负结论。</td></tr><tr><td>履约门</td><td>毛利、库存、发货、客服压力、退款投诉不达标时禁止放量。</td></tr><tr><td>知识门</td><td>规则入库必须写明适用条件和失效条件，不能把一次偶然胜出写成永久规律。</td></tr></tbody></table><p>普通食品素材合规清单：</p><table tabindex="0"><thead><tr><th>等级</th><th>表达/内容</th><th>处理原则</th></tr></thead><tbody><tr><td>禁止</td><td>疾病预防、治疗、缓解症状、调理疾病、降尿酸、养胃、治胃病、改善三高等表述。</td><td>普通食品不能按药品或保健食品宣传。</td></tr><tr><td>禁止</td><td>最、第一、全网最低、行业唯一、永久有效、绝对安全等绝对化或无法证明表达。</td><td>除非有清晰合法证明并经过负责人复核，否则不进入素材。</td></tr><tr><td>禁止</td><td>AI 生成的工厂、检测、证书、真实用户反馈画面冒充真实素材。</td><td>工厂、资质、用户原话必须来自真实资产或记录。</td></tr><tr><td>需复核</td><td>无添加、防腐剂、真材实料、工厂直发、源头价、儿童爱吃、老人适合。</td><td>必须由品控、供应链或合规确认可证明。</td></tr><tr><td>需复核</td><td>价格、券后价、包邮、发货时效、库存充足、组合规格。</td><td>必须与店铺链接和库存事实一致。</td></tr><tr><td>允许</td><td>口味、制作方式、食用场景、储存方式、烹饪便利性、真实包装展示。</td><td>仍需保证画面和文字与事实包一致。</td></tr></tbody></table><h2 id="十三、数据决策规则" tabindex="-1">十三、数据决策规则 <a class="header-anchor" href="#十三、数据决策规则" aria-label="Permalink to &quot;十三、数据决策规则&quot;">​</a></h2><table tabindex="0"><thead><tr><th>规则</th><th>触发条件</th><th>动作</th></tr></thead><tbody><tr><td>样本资格</td><td>单个实验单元曝光、点击、转化样本达到预设观察下限，或运行满观察窗口且花费达到单元预算上限。</td><td>不足样本只标记为观察中，不输出胜负结论。阈值应在 3-5 轮后按公司基线重校准。</td></tr><tr><td>封面胜出</td><td>同一人群和同一钩子下，某封面入口点击表现明显更好，且 3 秒留存没有明显下降。</td><td>保留封面方向进入二创；若点击高但留存低，判定入口承诺与开头承接不一致。</td></tr><tr><td>钩子胜出</td><td>同一人群和同一封面下，某钩子 3 秒留存更好，且后续加购不恶化。</td><td>保留钩子结构，下一轮测试叙事主体。</td></tr><tr><td>承接失败</td><td>点击、3 秒留存正常，但加购、成交、咨询转化偏弱。</td><td>优先检查商品页、价格、规格、评价、客服话术，不直接否定素材。</td></tr><tr><td>经营暂停</td><td>ROI 短期较好但毛利不足、库存不足、退款投诉上升或客服压力异常。</td><td>禁止放量，先修正履约和承接。</td></tr><tr><td>合规暂停</td><td>出现医疗化、功效化、绝对化、价格不一致、AI 伪真实画面等风险。</td><td>立即下线或退回修改，复盘中单独记录合规失败。</td></tr><tr><td>可放量</td><td>入口、留存、加购/成交、毛利、库存、客服和合规同时通过。</td><td>小幅递增预算，并同步生产二创版本，避免单条素材疲劳。</td></tr></tbody></table><h2 id="十四、落地顺序" tabindex="-1">十四、落地顺序 <a class="header-anchor" href="#十四、落地顺序" aria-label="Permalink to &quot;十四、落地顺序&quot;">​</a></h2><table tabindex="0"><thead><tr><th>顺序</th><th>动作</th><th>验收标准</th></tr></thead><tbody><tr><td>先建表</td><td>搭建素材实验主表、事实包表、素材资产库、浏览器自动化任务表、审核记录表、投放数据回写表、知识规则库。</td><td>任何素材都能找到实验编号、责任人、状态、事实包、审核记录和数据回写。</td></tr><tr><td>再接 AI</td><td>把情报、脚本、封面、合规、归因、知识库 Agent 接到对应字段。</td><td>AI 输出不再散落在聊天记录中，而是进入可审核字段。</td></tr><tr><td>再接浏览器自动化</td><td>从只读巡检、截图、下载、预填开始，不碰发布和预算。</td><td>每次自动化运行都有任务记录、截图证据、异常结果和人审状态。</td></tr><tr><td>再跑最小实验</td><td>用 1 个 SKU、2 类人群、2 类封面、2 类钩子完成一轮闭环。</td><td>能完成立项、事实确认、素材制作、审核、小量上线、数据回写、复盘入库。</td></tr><tr><td>再扩大规模</td><td>跑通后扩展到更多 SKU、更多素材类型、更多渠道和更高自动化权限。</td><td>扩大前必须有权限边界、风险回滚、异常报警和负责人确认机制。</td></tr></tbody></table><p>本方案中的“完美”不等于自动爆款，也不等于全自动无人参与。它指的是：素材生产有事实约束，创意变量可归因，部门协作不空转，浏览器后台动作可自动化且可审计，AI 输出可结构化入表，合规风险可阻断，投放数据可回写，胜出经验可沉淀，失败样本可复用。</p>',33))])}const f=e(o,[["render",n]]);export{g as __pageData,f as default};
